import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"设置股价提醒","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"getting-started/price-alert.md","filePath":"zh-CN/getting-started/price-alert.md"}'),l={name:"getting-started/price-alert.md"};function i(n,a,p,s,h,d){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="设置股价提醒" tabindex="-1">设置股价提醒 <a class="header-anchor" href="#设置股价提醒" aria-label="Permalink to &quot;设置股价提醒&quot;">​</a></h1><p>在本教程结束时，你将为一只股票设置好价格提醒，当它触达目标价时，你的手机会收到推送通知。</p><p>这个教程只需要 <strong>3 分钟</strong>，不需要在交易时间内操作。</p><h2 id="开始前的准备" tabindex="-1">开始前的准备 <a class="header-anchor" href="#开始前的准备" aria-label="Permalink to &quot;开始前的准备&quot;">​</a></h2><p>确认手机已开启长桥 App 的通知权限：</p><ul><li><strong>iPhone</strong>：设置 → 长桥 App → 通知 → 允许通知</li><li><strong>Android</strong>：设置 → 应用管理 → 长桥 → 通知 → 开启</li></ul><p>没有开启通知权限，提醒触发后你不会收到推送。</p><h2 id="第一步-进入股票详情页" tabindex="-1">第一步：进入股票详情页 <a class="header-anchor" href="#第一步-进入股票详情页" aria-label="Permalink to &quot;第一步：进入股票详情页&quot;">​</a></h2><p>点击 App 任意页面右上角的<strong>搜索图标（🔍）</strong>。</p><p>在搜索框中输入一只你想关注的股票，例如<strong>腾讯控股</strong>或 <strong>00700</strong>，点击搜索结果进入详情页。</p><p>你会看到股票当前价格、今日涨跌幅和 K 线图。</p><h2 id="第二步-找到价格提醒入口" tabindex="-1">第二步：找到价格提醒入口 <a class="header-anchor" href="#第二步-找到价格提醒入口" aria-label="Permalink to &quot;第二步：找到价格提醒入口&quot;">​</a></h2><p>在股票详情页，注意页面右上角有一个<strong>铃铛图标（🔔）</strong>。</p><p>点击它。</p><p>你会看到「添加提醒」面板从下方弹出，显示该股票的当前价格。</p><h2 id="第三步-设置提醒条件" tabindex="-1">第三步：设置提醒条件 <a class="header-anchor" href="#第三步-设置提醒条件" aria-label="Permalink to &quot;第三步：设置提醒条件&quot;">​</a></h2><p>面板中有两个主要设置：</p><p><strong>提醒方向</strong>：</p><ul><li><strong>价格高于</strong>：当股价涨到某个价格时提醒你（例如想在股价突破高位时知道）</li><li><strong>价格低于</strong>：当股价跌到某个价格时提醒你（例如想在股价回调到心理价位时买入）</li></ul><p>选择你需要的方向。我们以**「价格低于」**为例，模拟设置一个买入观察点。</p><p><strong>目标价格</strong>：</p><p>在价格输入栏填入你的目标价。例如，如果当前股价是 380，你想在跌到 360 时收到通知，就输入 <strong>360</strong>。</p><p>注意：价格栏已预填了当前市价，直接修改成你的目标价即可。</p><h2 id="第四步-确认提交" tabindex="-1">第四步：确认提交 <a class="header-anchor" href="#第四步-确认提交" aria-label="Permalink to &quot;第四步：确认提交&quot;">​</a></h2><p>检查一遍：</p><ul><li>股票名称正确</li><li>提醒方向正确（高于 / 低于）</li><li>目标价格正确</li></ul><p>点击**「确认」<strong>或</strong>「添加提醒」**按钮。</p><p>你会看到页面提示「提醒设置成功」，铃铛图标变为实心，表示该股票已有活跃提醒。</p><h2 id="第五步-查看已设置的提醒" tabindex="-1">第五步：查看已设置的提醒 <a class="header-anchor" href="#第五步-查看已设置的提醒" aria-label="Permalink to &quot;第五步：查看已设置的提醒&quot;">​</a></h2><p>你可以随时查看和管理所有提醒：</p><p>点击 App 右上角的<strong>通知图标</strong>，选择**「我的提醒」**（或在股票详情页再次点击铃铛图标）。</p><p>你会看到刚才设置的提醒出现在列表中，显示股票名称、条件和目标价。</p><h2 id="当提醒触发时" tabindex="-1">当提醒触发时 <a class="header-anchor" href="#当提醒触发时" aria-label="Permalink to &quot;当提醒触发时&quot;">​</a></h2><p>当该股票价格达到你设置的目标价时，你的手机会收到一条推送通知，通知内容会显示「腾讯控股已跌破 360 港元」（或类似文字）。</p><p>点击通知会直接跳转到该股票详情页，你可以在那里决定是否采取行动。</p><p>提醒触发一次后会自动失效，如果你还想继续追踪，可以重新设置。</p><h2 id="确认完成" tabindex="-1">确认完成 <a class="header-anchor" href="#确认完成" aria-label="Permalink to &quot;确认完成&quot;">​</a></h2><p><strong>恭喜！你已经学会了三项基本操作：</strong></p><ol><li>✅ 完成首次入金 — 账户有了港元资金</li><li>✅ 买入第一只港股 — 完成了第一笔交易</li><li>✅ 设置股价提醒 — 市场波动时能第一时间知道</li></ol><hr><p>接下来，你可以进一步了解：</p><ul><li><a href="/交易市场与规则/港股交易规则与结算">港股交易规则与结算</a> — 交易时间、T+2 交收等规则说明</li><li><a href="/订单类型/限价单与市价单">订单类型说明</a> — 限价单、市价单等更多下单方式</li><li><a href="/portfolio-and-statements/资产设置">资产设置</a> — 自定义持仓页面的显示偏好</li></ul>',42)])])}const u=t(l,[["render",i]]);export{c as __pageData,u as default};
